import{c as a,Q as t,j as i,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Garry Tan's Thin Harness, Fat Skills: Five Concepts Unpacked","description":"","frontmatter":{"url":"https://yage.ai/share/thin-harness-fat-skills-en-20260414.html","title":"Garry Tan's Thin Harness, Fat Skills: Five Concepts Unpacked","author":"Garry Tan (Yage AI)","date":"2026-04-14T00:00:00.000Z","status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/41-yageai-thin-harness-fat-skills.md","filePath":"research/ai-articles/41-yageai-thin-harness-fat-skills.md","lastUpdated":1779894392000}`),r={name:"research/ai-articles/41-yageai-thin-harness-fat-skills.md"};function n(l,e,o,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="garry-tan-s-thin-harness-fat-skills-five-concepts-unpacked" tabindex="-1">Garry Tan&#39;s Thin Harness, Fat Skills: Five Concepts Unpacked <a class="header-anchor" href="#garry-tan-s-thin-harness-fat-skills-five-concepts-unpacked" aria-label="Permalink to &quot;Garry Tan&#39;s Thin Harness, Fat Skills: Five Concepts Unpacked&quot;">​</a></h1><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><p>Garry argues the harness (the program running the model) should remain minimal, handling only four essential functions: &quot;run the model in a loop, read and write files, manage context, and enforce safety.&quot;</p><h2 id="the-problem-with-fat-harnesses" tabindex="-1">The Problem with Fat Harnesses <a class="header-anchor" href="#the-problem-with-fat-harnesses" aria-label="Permalink to &quot;The Problem with Fat Harnesses&quot;">​</a></h2><p>He opposes bloated architectures with excessive tool definitions. These consume significant context window space and introduce performance bottlenecks. His quantified example illustrates the issue: a Playwright CLI executes browser operations in 100ms, while a Chrome MCP requires 15 seconds for the same screenshot-find-click-wait-read sequence—a 75x performance gap.</p><h2 id="the-solution-directional-architecture" tabindex="-1">The Solution: Directional Architecture <a class="header-anchor" href="#the-solution-directional-architecture" aria-label="Permalink to &quot;The Solution: Directional Architecture&quot;">​</a></h2><p>The design principle pushes intelligence upward into reusable skill files and execution capability downward into deterministic tools. The middle layer stays as thin as possible.</p><h2 id="key-insight" tabindex="-1">Key Insight <a class="header-anchor" href="#key-insight" aria-label="Permalink to &quot;Key Insight&quot;">​</a></h2><p>&quot;Every skill you write is a permanent upgrade to your system.&quot; Skills remain stable and benefit automatically when models improve, while deterministic steps maintain reliability. This architecture separates the cognitive judgment layer (model-driven) from the execution layer (tool-driven), enabling scalability without context bloat.</p>',9)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
